#!/usr/bin/env python3
"""Add/refresh the 10 game sounds (MP3) in assets/assets.json, ids a117-a126.
Run once from your repo root:  python3 apply_audio.py
Backs up assets.json to assets.json.bak, sets the audio entries (leaves every
other asset untouched), refreshes manifest.json if present. Safe to re-run;
also correctly REPLACES any earlier OGG audio that used these ids.
"""
import json, os, sys, hashlib
HERE=os.path.dirname(os.path.abspath(__file__))
ASSETS=os.path.join(HERE,"assets","assets.json"); MANIFEST=os.path.join(HERE,"manifest.json")
LABELS={"a117": "card_slide", "a118": "card_place", "a119": "card_shove", "a120": "card_shuffle", "a121": "book_flip", "a122": "card_fan", "a123": "pack_open", "a124": "pack_take", "a125": "battle_music", "a126": "tape_noise"}
NEW={
  "a117": "",
  "a118": "",
  "a119": "",
  "a120": "",
  "a121": "",
  "a122": "",
  "a123": "",
  "a124": "",
  "a125": "",
  "a126": "",
}
def main():
    if not os.path.exists(ASSETS): sys.exit(f"[audio] ERROR: {ASSETS} not found. Run from your repo root.")
    assets=json.load(open(ASSETS)); bak=ASSETS+".bak"
    if not os.path.exists(bak):
        json.dump(assets,open(bak,"w"),separators=(",",":")); print(f"[audio] backup: {bak}")
    for aid,b64 in NEW.items():
        tag="added" if aid not in assets else ("unchanged" if assets[aid]==b64 else "replaced")
        assets[aid]=b64; print(f"[audio] {aid}  {LABELS.get(aid,aid):14s} {tag}")
    json.dump(assets,open(ASSETS,"w"),separators=(",",":")); print(f"[audio] wrote {ASSETS}")
    if os.path.exists(MANIFEST):
        try:
            man=json.load(open(MANIFEST)); have={r.get("id") for r in man.get("assets",[])}
            for aid,b64 in NEW.items():
                rec={"id":aid,"media_type":"audio/mpeg","bytes_b64":len(b64),"sha256":hashlib.sha256(b64.encode()).hexdigest(),"occurrences":1}
                if aid in have:
                    for r in man["assets"]:
                        if r.get("id")==aid: r.update(rec)
                else: man.setdefault("assets",[]).append(rec)
            json.dump(man,open(MANIFEST,"w"),indent=1); print("[audio] manifest refreshed")
        except Exception as e: print(f"[audio] (manifest skip: {e})")
    print("\n[audio] Done. Next: swap in the new game.src.html, then python3 build.py")
if __name__=="__main__": main()
